+        }
+    }
+
+    fn cycle_log_rate(&mut self) {
+        self.log_rate_idx = (self.log_rate_idx + 1) % LOG_RATE_OPTIONS.len();
+    }
+
+    fn cycle_ui_height(&mut self) {
+        self.ui_height_idx = (self.ui_height_idx + 1) % UI_HEIGHT_OPTIONS.len();
+    }
