+        );
+        let line2 = format!(
+            "Status: {paused_label}  |  Lines: {}  |  Scrollback preserved in inline mode",
+            self.lines_generated
+        );
+
+        let text = if area.height >= 2 {
+            format!("{line1}\n{line2}")
+        } else {
+            line1
+        };
+
+        Paragraph::new(text)
+            .style(Style::new().fg(theme::fg::PRIMARY))
+            .render(area, frame);
