+
+    fn render_alt_header(&self, frame: &mut Frame, area: Rect) {
+        if area.is_empty() {
+            return;
+        }
+        let text = if area.height >= 2 {
+            " ALT-SCREEN MODE - SCROLLBACK HIDDEN \n Full-screen takeover (logs do not persist)"
