+
+    fn render_inline_pane(&self, frame: &mut Frame, area: Rect, title: &str) {
+        if area.is_empty() {
+            return;
+        }
+        let block = Block::new()
+            .borders(Borders::ALL)
+            .border_type(BorderType::Rounded)
+            .title(title)
+            .style(Style::new().fg(theme::fg::PRIMARY));
+        let inner = block.inner(area);
+        block.render(area, frame);
+        if inner.is_empty() {
