+                action: "Toggle overlay",
+            },
+            HelpEntry {
+                key: "t",
+                action: "Toggle tree panel",
+            },
+            HelpEntry {
+                key: "r",
+                action: "Reset step",
+            },
+        ]
+    }
+
+    fn title(&self) -> &'static str {
+        "Layout Inspector"
+    }
+
+    fn tab_label(&self) -> &'static str {
+        "Layout"
+    }
+}
