+                Span::raw(" md "),
+                Span::styled(
+                    format!("{rendered_w:>3}"),
+                    Style::new().fg(theme::fg::PRIMARY),
+                ),
+                Span::raw(" Δ "),
+                Span::styled(format!("{delta:+}"), delta_style),
+            ]));
+        }
+
+        Paragraph::new(Text::from_lines(lines)).render(inner, frame);
+    }
