+            },
+            HelpEntry {
+                key: "Ctrl+↑/↓",
+                action: "Scroll preview",
+            },
+        ]
+    }
+
+    fn title(&self) -> &'static str {
+        "Live Markdown"
+    }
+
+    fn tab_label(&self) -> &'static str {
+        "MD Live"
+    }
+}

